def solve(vals_str):
    vals = vals_str.split()
    from collections import deque
    nodes = [None if v == 'null' else int(v) for v in vals]
    if not nodes: return 'true'
    # BFS using array representation
    n = len(nodes)
    found_null = False
    for i in range(n):
        if nodes[i] is None:
            found_null = True
        elif found_null:
            return 'false'
    # Also check structural completeness (no child after missing parent)
    for i in range(n):
        left = 2*i+1; right = 2*i+2
        if nodes[i] is None:
            if left < n and nodes[left] is not None: return 'false'
            if right < n and nodes[right] is not None: return 'false'
    return 'true'

